    def test_version_commands_report_running_cli_and_project_pin_status(self) -> None:
        code, output = self.run_cli(["--version"])
        self.assertEqual(code, 0, output)
        self.assertEqual(output.strip(), f"archive {archive_cli.__version__}")

        with tempfile.TemporaryDirectory() as tmp:
            project_root = Path(tmp) / "project"
            pin_dir = project_root / ".zettel-kasten" / "source"
            pin_dir.mkdir(parents=True)
            (pin_dir / "installed-version.txt").write_text("\ufeffv0.0.1\n", encoding="utf-8")

            json_code, json_output = self.run_cli(["version", str(project_root), "--format", "json"])
            result = json.loads(json_output)
            self.assertEqual(json_code, 1, json_output)
            self.assertFalse(result["ok"])
            self.assertEqual(result["lifecycle_action"], "wom_kit_version")
            self.assertEqual(result["version"], archive_cli.__version__)
            self.assertEqual(result["version_label"], f"v{archive_cli.__version__}")
            self.assertEqual(result["source_of_truth"], "wom_kit.__version__")
            self.assertTrue(result["pyproject_matches_package_version"])
            self.assertEqual(result["project_pin"]["status"], "present")
            self.assertEqual(result["project_pin"]["path"], ".zettel-kasten/source/installed-version.txt")
            self.assertEqual(result["project_pin"]["pin_root"], "inspection_root")
            self.assertEqual(result["project_pin"]["installed_version"], "v0.0.1")
            self.assertFalse(result["project_pin"]["matches_package_version"])
            self.assertIn(
                ".zettel-kasten/source/installed-version.txt",
                result["project_pin"]["checked_locations"],
            )
            self.assertEqual(result["consistency_state"], "project_pin_mismatch")
            self.assertEqual(result["canonical_checks"]["human_readable"], "archive --version")
            self.assertTrue(result["redaction"]["local_paths_redacted"])
            self.assertNotIn("local_paths", result)
            self.assertNotIn(str(project_root), json_output)

            (pin_dir / "installed-version.txt").write_text(f"v{archive_cli.__version__}\n", encoding="utf-8")
            ok_code, ok_output = self.run_cli(["version", str(project_root), "--format", "json"])
            ok_result = json.loads(ok_output)
            self.assertEqual(ok_code, 0, ok_output)
            self.assertTrue(ok_result["ok"])
            self.assertTrue(ok_result["project_pin"]["matches_package_version"])
            self.assertEqual(ok_result["consistency_state"], "source_checkout_match")

    def test_version_command_finds_parent_project_pin_from_archive_root(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            project_root = Path(tmp) / "project"
            archive_root = project_root / "archive"
            archive_root.mkdir(parents=True)
            (archive_root / "archive.yml").write_text(
                "archive_id: archive:personal:fake-life\narchive_type: personal\n",
                encoding="utf-8",
            )
            pin_dir = project_root / ".zettel-kasten"
            pin_dir.mkdir()
            (pin_dir / "installed-version.txt").write_text("v0.0.1\n", encoding="utf-8")

            code, output = self.run_cli(["version", str(archive_root), "--format", "json"])
            result = json.loads(output)

            self.assertEqual(code, 1, output)
            self.assertFalse(result["ok"])
            self.assertEqual(result["project_pin"]["status"], "present")
            self.assertEqual(result["project_pin"]["path"], "parent_of_archive/.zettel-kasten/installed-version.txt")
            self.assertEqual(result["project_pin"]["pin_root"], "parent_of_archive")
            self.assertEqual(result["project_pin"]["installed_version"], "v0.0.1")
            self.assertFalse(result["project_pin"]["matches_package_version"])
            self.assertIn(
                "parent_of_archive/.zettel-kasten/installed-version.txt",
                result["project_pin"]["checked_locations"],
            )
            self.assertEqual(result["consistency_state"], "project_pin_mismatch")
            self.assertTrue(result["redaction"]["local_paths_redacted"])
            self.assertNotIn(str(project_root), output)
            self.assertNotIn(str(archive_root), output)

    def test_profile_list_reads_example_registry_and_redacts_paths(self) -> None:
        registry = KIT_ROOT / "templates" / "profiles" / "wom-profiles.example.yml"
        code, output = self.run_cli(["profile-list", "--registry", str(registry), "--format", "json"])

        self.assertEqual(code, 0, output)
        result = json.loads(output)
        self.assertTrue(result["ok"])
        self.assertEqual(result["lifecycle_action"], "profile_list")
        self.assertEqual(result["registry_path"], "<local-path-redacted>")
        self.assertEqual(result["default_profile"], "profile:personal:me")
        self.assertEqual(len(result["profiles"]), 3)
        self.assertEqual(result["profiles"][0]["archive_root"], "<local-path-redacted>")
        self.assertEqual(result["profiles"][0]["token_state"], "present")
        self.assertEqual(result["profiles"][1]["token_state"], "missing")
        self.assertEqual(result["profiles"][2]["profile_id"], "profile:person:wallet-ready-example")
        self.assertNotIn("token_ref", json.dumps(result))

    def test_profile_resolve_exact_profile_id_match_succeeds(self) -> None:
        registry = KIT_ROOT / "templates" / "profiles" / "wom-profiles.example.yml"
        code, output = self.run_cli(
            [
                "profile-resolve",
                "--registry",
                str(registry),
                "--target",
                "profile:personal:me",
                "--format",
                "json",
            ]
        )

        self.assertEqual(code, 0, output)
        result = json.loads(output)
        self.assertTrue(result["ok"])
        self.assertEqual(result["resolution_state"], "resolved")
        self.assertEqual(result["selected_profile"]["profile_id"], "profile:personal:me")
        self.assertTrue(result["direct_write_available"])
        self.assertEqual(result["suggested_next_action"], "run_runtime_context")
        self.assertEqual(result["runtime_context_args_preview"]["expected_archive_id"], "archive:personal:me")
        self.assertEqual(result["runtime_context_args_preview"]["expected_type"], "personal")
        self.assertEqual(result["runtime_context_args_preview"]["archive_root"], "<local-path-redacted>")

    def test_profile_resolve_exact_label_and_alias_match_succeed(self) -> None:
        registry = KIT_ROOT / "templates" / "profiles" / "wom-profiles.example.yml"
        label_code, label_output = self.run_cli(
            ["profile-resolve", "--registry", str(registry), "--target", "Personal archive", "--format", "json"]
        )
        alias_code, alias_output = self.run_cli(
            ["profile-resolve", "--registry", str(registry), "--target", "PERSONAL", "--format", "json"]
        )

        self.assertEqual(label_code, 0, label_output)
        self.assertEqual(alias_code, 0, alias_output)
        self.assertEqual(json.loads(label_output)["matches"][0]["match_type"], "label")
