    def test_runtime_context_returns_deterministic_redacted_json(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            archive_root = self.copy_fake_archive(Path(tmp) / "archive")

            args = ["runtime-context", str(archive_root), "--format", "json"]
            first_code, first_output = self.run_cli(args)
            second_code, second_output = self.run_cli(args)

            self.assertEqual(first_code, 0, first_output)
            self.assertEqual(second_code, 0, second_output)
            self.assertEqual(json.loads(first_output), json.loads(second_output))
            self.assertNotIn(str(archive_root), first_output)

            result = json.loads(first_output)
            self.assertTrue(result["ok"])
            self.assertEqual(result["lifecycle_action"], "runtime_context")
            self.assertEqual(result["archive_id"], "archive:personal:fake-life")
            self.assertEqual(result["archive_type"], "personal")
            self.assertEqual(result["scope"], "personal")
            self.assertEqual(
                result["paths"],
                {
                    "inbox": "inbox/",
                    "zettels": "zettels/",
                    "receipts": "receipts/",
                    "operational_context": "ops/operational-context.yml",
                    "object_manifest": "objects/manifests/files.jsonl",
                },
            )
            self.assertTrue(result["redaction"]["local_paths_redacted"])
            self.assertNotIn("local_archive_root", result)
            self.assertNotIn("local_paths", result)
            self.assertEqual(result["wom_kit_version"]["version"], archive_cli.__version__)
            self.assertEqual(result["wom_kit_version"]["version_label"], f"v{archive_cli.__version__}")
            self.assertEqual(result["wom_kit_version"]["source_of_truth"], "wom_kit.__version__")
            self.assertEqual(result["wom_kit_version"]["project_pin"]["status"], "missing")
            self.assertTrue(result["wom_kit_version"]["redaction"]["local_paths_redacted"])
            self.assertNotIn("local_paths", result["wom_kit_version"])
            operational_context = result["operational_context"]
            self.assertTrue(operational_context["ok"])
            self.assertEqual(operational_context["lifecycle_action"], "operational_context")
            self.assertEqual(operational_context["status"], "present")
            self.assertEqual(operational_context["record_path"], "ops/operational-context.yml")
            self.assertIn("session resets", operational_context["record"]["mission"]["summary"])
            self.assertEqual(
                operational_context["session_start_injection"]["source"],
                "ops/operational-context.yml",
            )
            self.assertIn("Run runtime-context first.", operational_context["session_start_injection"]["next"])
            self.assertTrue(operational_context["closed_actions"]["file_body_read"])
            self.assertFalse(operational_context["closed_actions"]["files_written"])
            entrypoints = result["canonical_entrypoints"]
            self.assertEqual(entrypoints["lifecycle_action"], "runtime_canonical_entrypoints")
            self.assertEqual(entrypoints["start_here"], "archive.yml")
            self.assertEqual(entrypoints["source_truths"]["archive_identity_and_policy"], "archive.yml")
            self.assertEqual(entrypoints["source_truths"]["canonical_zets"], "zettels/")
            self.assertEqual(entrypoints["source_truths"]["draft_inbox"], "inbox/")
            self.assertEqual(entrypoints["source_truths"]["objet_manifest"], "objects/manifests/files.jsonl")
            self.assertEqual(entrypoints["source_truths"]["operational_context"], "ops/operational-context.yml")
            self.assertEqual(
                entrypoints["recommended_first_commands"][0]["command"],
                "archive runtime-context <archive-root> --format json",
            )
            self.assertEqual(
                entrypoints["recommended_first_commands"][1]["command"],
                "archive operational-context <archive-root> --dry-run --format json",
            )
            self.assertEqual(
                entrypoints["recommended_first_commands"][2]["command"],
                "archive ai-response-concept-guide <archive-root> --topic all --dry-run --format json",
            )
            self.assertEqual(
                [step["action"] for step in entrypoints["ai_runtime_order"]],
                [
                    "run_runtime_context",
                    "read_operational_context",
                    "read_canonical_entrypoints",
                    "read_local_agent_instructions",
                    "run_ai_response_concept_guide",
                    "choose_material_link_route",
                ],
            )
            material_commands = [route["command"] for route in entrypoints["material_link_routes"]]
            self.assertTrue(any("notion-objet-import-clue-audit" in command for command in material_commands))
            self.assertTrue(any("notion-objet-source-map-link-plan" in command for command in material_commands))
            self.assertTrue(any("notion-objet-link-index" in command for command in material_commands))
            self.assertTrue(any("notion-objet-link-plan" in command for command in material_commands))
            self.assertTrue(all(route["writes"] is False for route in entrypoints["material_link_routes"]))
            self.assertTrue(all(route["provider_api_called"] is False for route in entrypoints["material_link_routes"]))
            self.assertFalse(entrypoints["closed_actions"]["file_bodies_read"])
            self.assertFalse(entrypoints["closed_actions"]["files_written"])
            self.assertFalse(entrypoints["closed_actions"]["provider_api_called"])
            self.assertFalse(entrypoints["closed_actions"]["secrets_read"])
            entrypoint_statuses = {item["path"]: item for item in entrypoints["read_order"]}
