            self.assertNotIn(candidate_refs[1], approve_output)
            self.assertNotIn(str(archive_root), approve_output)

            bad_receipt = "receipts/imap/adapter-executions/imap-header-metadata-scan-bad.json"
            bad_payload = json.loads(json.dumps(receipt_payload))
            bad_payload["redaction"]["headers_included"] = True
            (archive_root / bad_receipt).write_text(json.dumps(bad_payload), encoding="utf-8")
            bad_code, bad_output = self.run_cli(
                [
                    "imap-header-scan-receipt-audit",
                    str(archive_root),
                    "--execution-receipt",
                    bad_receipt,
                    "--dry-run",
                    "--format",
                    "json",
                ]
            )
            bad_result = json.loads(bad_output)
            self.assertEqual(bad_code, 1, bad_output)
            self.assertFalse(bad_result["ok"])
            self.assertEqual(bad_result["audit_state"], "blocked")
            self.assertIn("headers_included", bad_result["redaction_check"]["failed_flags"])
            self.assertNotIn(bad_receipt, bad_output)
            self.assertNotIn(str(archive_root), bad_output)

