                    "draft_only",
                    "--creation-mode",
                    "ai_assisted",
                    "--created-by",
                    "ai_runtime:codex",
                    "--source",
                    "user_conversation",
                    "--assisted-by",
                    "ai_runtime:codex",
                    "--supervised-by",
                    "person:test",
                    "--derived-from",
                    "object:example-script",
                    "--source-ref",
                    "local_ai_session:session:approved",
                    "--local-ai-session",
                    "session:approved",
                    "--draft-id",
                    "zet_20260524_020304_approved_ai_draft",
                    "--created-at",
                    "2026-05-24T02:03:04+09:00",
