            dry_code, dry_output = self.run_cli(
                [
                    "retire-draft",
                    str(archive_root),
                    "--zettel-id",
                    "zet_20260519_draft_ai_lunch_note",
                    "--dry-run",
                    "--format",
                    "json",
                ]
            )
            self.assertEqual(dry_code, 0, dry_output)
            dry_result = json.loads(dry_output)
