class ObjetCaptureTests(unittest.TestCase):
    maxDiff = None

    def run_cli(self, args: list[str]) -> tuple[int, str]:
        buffer = io.StringIO()
        with redirect_stdout(buffer), redirect_stderr(buffer):
            code = archive_cli.main(args)
        return code, buffer.getvalue()

    def _sandbox(self, tmp: str, archive_id: str = "archive:personal:capture") -> Path:
        archive_root = Path(tmp) / "capture-archive"
        code, output = self.run_cli(
            [
                "init",
                str(archive_root),
                "--type",
                "personal",
                "--archive-id",
                archive_id,
                "--principal-id",
                "person:test",
            ]
        )
        self.assertEqual(code, 0, output)
        (archive_root / ".wom-sandbox").write_text("sandbox\n", encoding="utf-8")
        (archive_root / "staging" / "incoming").mkdir(parents=True, exist_ok=True)
        return archive_root

    def _stage(self, archive_root: Path, name: str, data: bytes) -> tuple[str, str]:
        staged = archive_root / "staging" / "incoming" / name
        staged.write_bytes(data)
        return f"staging/incoming/{name}", hashlib.sha256(data).hexdigest()

    def _plan(self, archive_root: Path, name: str = "plan") -> tuple[str, str]:
        plan = {
            "ok": True,
            "dry_run": True,
            "lifecycle_action": "source_intake_plan",
            "blockers": [],
            "content_access": dict(archive_services.SOURCE_INTAKE_CONTENT_ACCESS_EXPECTATIONS),
            "source_refs_for_draft": [],
        }
        plan_dir = archive_root / "receipts" / "sources"
        plan_dir.mkdir(parents=True, exist_ok=True)
        relative = f"receipts/sources/{name}.source-intake-plan.json"
        (archive_root / Path(relative)).write_text(json.dumps(plan), encoding="utf-8")
        return relative, archive_services.sha256_json_value(plan)

    def _project_intake_receipt(self, tmp: str, archive_root: Path) -> str:
        decisions_path = Path(tmp) / "project-intake-decisions.json"
        decisions_path.write_text(
            json.dumps(
                {
                    "schema": "wom-kit/project-intake-decisions/v0.1",
                    "session_id": "alpha-project-20260613",
                    "decisions": [
                        {
                            "checklist_id": "scope.single_project",
                            "answer": "yes",
                            "notes": "One project only.",
                        }
                    ],
                }
            ),
            encoding="utf-8",
        )
        result = archive_services.project_intake_decisions(
            archive_root,
            decisions_path,
            approve=True,
            reviewed_by="person:test",
        )
        self.assertTrue(result["ok"], result)
        return str(result["receipt_path"])

    def _item(
        self,
        staged_path: str,
        digest: str,
        plan_path: str,
        plan_sha: str,
        item_id: str = "item",
        **overrides: Any,
    ) -> dict[str, Any]:
        item = {
            "item_id": item_id,
            "approved": True,
            "input_kind": "local_path",
            "staged_path": staged_path,
            "approved_object_id": f"sha256:{digest}",
            "source_intake_receipt_path": plan_path,
            "source_intake_plan_sha256": plan_sha,
        }
        item.update(overrides)
        return item

    def _selection(
        self,
        tmp: str,
        archive_id: str,
        items: list[dict[str, Any]],
        **overrides: Any,
    ) -> Path:
        selection = {
            "manifest_id": "approved:local-objet-capture:test",
            "schema": "wom-kit/b4-selection/v0.2",
            "action": "local_objet_capture_approved",
            "archive_id": archive_id,
            "items": items,
            "privacy_guards": {key: True for key in archive_services.OBJET_CAPTURE_REQUIRED_PRIVACY_GUARDS},
        }
        selection.update(overrides)
        path = Path(tmp) / "selection.json"
        path.write_text(json.dumps(selection), encoding="utf-8")
        return path

    def _simple_capture_setup(self, tmp: str, data: bytes = b"objet bytes\n") -> tuple[Path, Path, str]:
        archive_root = self._sandbox(tmp)
        staged_path, digest = self._stage(archive_root, "note.txt", data)
        plan_path, plan_sha = self._plan(archive_root)
        selection = self._selection(
            tmp, "archive:personal:capture", [self._item(staged_path, digest, plan_path, plan_sha)]
        )
        return archive_root, selection, digest

    def _inventory(self, root: Path) -> dict[str, tuple[int, int]]:
        entries: dict[str, tuple[int, int]] = {}
        for path in sorted(root.rglob("*")):
            if path.is_file():
                file_stat = path.stat()
                entries[str(path.relative_to(root))] = (file_stat.st_size, file_stat.st_mtime_ns)
        return entries

    def test_objet_capture_dry_run_writes_nothing(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            archive_root, selection, digest = self._simple_capture_setup(tmp)
            before = self._inventory(archive_root)
            result = archive_services.objet_capture_dry_run(archive_root, selection)
            self.assertTrue(result["ok"], result)
            self.assertTrue(result["dry_run"])
            self.assertEqual(result["items"][0]["planned_action"], "capture")
            self.assertIn("proposed_receipt_path", result)
            self.assertEqual(self._inventory(archive_root), before, "dry-run must not write anything")
            self.assertFalse(list(archive_root.rglob("*.part-*")))

    def test_objet_capture_selection_approve_writes_selection_only_for_later_capture(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            archive_root = self._sandbox(tmp)
            staged_path, digest = self._stage(archive_root, "note.txt", b"selection bridge bytes")
            plan_path, plan_sha = self._plan(archive_root)
            before_manifest_records = archive_services.load_manifest_records(archive_root)

            code, output = self.run_cli(
                [
                    "objet-capture-selection",
                    str(archive_root),
                    "--staged-path",
                    staged_path,
                    "--source-intake-receipt",
                    plan_path,
                    "--item-id",
                    "note-1",
                    "--approve",
                    "--reviewed-by",
                    "person:test",
                    "--format",
                    "json",
                ]
            )

            self.assertEqual(code, 0, output)
            result = json.loads(output)
            self.assertTrue(result["ok"], result)
            self.assertEqual(result["lifecycle_action"], "objet_capture_selection_record")
            self.assertFalse(result["privacy_guards"]["objet_capture_run"])
            self.assertFalse(result["privacy_guards"]["object_manifest_appended"])
            self.assertFalse(result["privacy_guards"]["object_bytes_written"])
            self.assertEqual(result["item"]["approved_object_id"], f"sha256:{digest}")
            self.assertEqual(result["item"]["source_intake_plan_sha256"], plan_sha)

            selection_path = archive_root / Path(result["selection_path"])
            self.assertTrue(selection_path.is_file())
            selection = json.loads(selection_path.read_text(encoding="utf-8"))
            self.assertEqual(selection["action"], archive_services.OBJET_CAPTURE_SELECTION_ACTION)
            self.assertEqual(selection["items"][0]["approved_object_id"], f"sha256:{digest}")
            self.assertEqual(selection["items"][0]["expected_size_bytes"], len(b"selection bridge bytes"))
            self.assertEqual(selection["items"][0]["source_intake_receipt_path"], plan_path)
            self.assertEqual(archive_services.load_manifest_records(archive_root), before_manifest_records)
            self.assertFalse((archive_root / "objects" / "sha256" / digest[:2] / digest).exists())

            capture_preview = archive_services.objet_capture_dry_run(archive_root, selection_path)
            self.assertTrue(capture_preview["ok"], capture_preview)
            self.assertEqual(capture_preview["summary"]["would_capture"], 1)

    def test_objet_capture_selection_dry_run_writes_nothing(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            archive_root = self._sandbox(tmp)
            staged_path, digest = self._stage(archive_root, "note.txt", b"selection dry run")
            plan_path, _ = self._plan(archive_root)
            before = self._inventory(archive_root)

            code, output = self.run_cli(
                [
                    "objet-capture-selection",
                    str(archive_root),
                    "--staged-path",
                    staged_path,
                    "--source-intake-receipt",
                    plan_path,
                    "--dry-run",
                    "--format",
                    "json",
                ]
            )

            self.assertEqual(code, 0, output)
            result = json.loads(output)
            self.assertTrue(result["ok"], result)
            self.assertEqual(result["lifecycle_action"], "objet_capture_selection_plan")
            self.assertEqual(result["item"]["approved_object_id"], f"sha256:{digest}")
            self.assertTrue(result["privacy_guards"]["file_body_hashed"])
            self.assertFalse(result["privacy_guards"]["writes"])
            self.assertEqual(self._inventory(archive_root), before)
            self.assertTrue(result["proposed_selection_path"].startswith("receipts/objet-capture-selections/"))

    def test_objet_capture_dry_run_accepts_project_intake_receipt_context(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            archive_root, selection, _ = self._simple_capture_setup(tmp)
            receipt_path = self._project_intake_receipt(tmp, archive_root)
            before = self._inventory(archive_root)

            code, output = self.run_cli(
                [
                    "objet-capture",
                    str(archive_root),
                    "--selection",
                    str(selection),
                    "--project-intake-receipt",
                    receipt_path,
                    "--dry-run",
                    "--format",
                    "json",
                ]
            )

            self.assertEqual(code, 0, output)
            result = json.loads(output)
            self.assertTrue(result["ok"], result)
            context = result["project_intake_context"]
            self.assertTrue(context["provided"])
            self.assertTrue(context["ok"])
            self.assertEqual(context["receipt_path"], receipt_path)
            self.assertEqual(context["session_id"], "alpha-project-20260613")
            self.assertFalse(context["decision_values_included"])
            self.assertFalse(context["automatic_execution_authorized"])
            self.assertNotIn("One project only", output)
            self.assertNotIn('"answer"', output)
            self.assertEqual(self._inventory(archive_root), before, "dry-run must not write anything")

    def test_objet_capture_apply_records_project_intake_receipt_context(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            archive_root, selection, _ = self._simple_capture_setup(tmp)
            receipt_path = self._project_intake_receipt(tmp, archive_root)

            result = archive_services.objet_capture_apply(
                archive_root,
                selection,
                reviewed_by="person:test",
                project_intake_receipt=receipt_path,
            )

            self.assertTrue(result["ok"], result)
            self.assertEqual(result["project_intake_context"]["receipt_path"], receipt_path)
            capture_receipt = json.loads((archive_root / result["receipt_path"]).read_text(encoding="utf-8"))
