    def test_derive_text_toolchain_and_agent_contract_are_read_only(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            archive_root = self._sandbox(tmp, "archive:personal:derived-toolchain")
            before = self._inventory(archive_root)

            code, output = self.run_cli(
                ["derive-text-toolchain", str(archive_root), "--extension", ".ppt", "--dry-run", "--format", "json"]
            )
            result = json.loads(output)
            self.assertEqual(code, 0, output)
            self.assertTrue(result["ok"])
            self.assertEqual(result["lifecycle_action"], "derived_text_toolchain_recommendation")
            self.assertEqual(result["toolchain"]["format_family"], "legacy_office_binary")
            self.assertIn("LibreOffice headless conversion", result["toolchain"]["primary_tools"])
            self.assertFalse(result["closed_actions"]["parser_run"])
            self.assertFalse(result["privacy_guards"]["local_absolute_paths_echoed"])
            self.assertEqual(result["would_change"], [])
            self.assertEqual(self._inventory(archive_root), before)

            code, output = self.run_cli(
                ["derive-text", "toolchain", str(archive_root), "--extension", ".hwp", "--dry-run", "--format", "json"]
            )
            hwp = json.loads(output)
            self.assertEqual(code, 0, output)
            self.assertEqual(hwp["toolchain"]["format_family"], "hwp_or_hwpx")
            self.assertIn("pyhwp hwp5txt", hwp["toolchain"]["primary_tools"])

            code, output = self.run_cli(
                ["derive-text-agent-contract", str(archive_root), "--dry-run", "--format", "json"]
            )
            contract = json.loads(output)
            self.assertEqual(code, 0, output)
            self.assertEqual(contract["lifecycle_action"], "derived_text_agent_contract")
            self.assertEqual(contract["agent_operating_contract"]["default_posture"], "maximum_textual_objet_coverage")
            self.assertIn("derive-text coverage --dry-run", contract["agent_operating_contract"]["required_preflight_order"])
            self.assertFalse(contract["closed_actions"]["derived_text_written"])
            self.assertEqual(self._inventory(archive_root), before)

    def test_derive_text_doctor_reports_tool_readiness_without_paths_or_writes(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            archive_root = self._sandbox(tmp, "archive:personal:derived-doctor")
            before = self._inventory(archive_root)

            def fake_module_available(module_name: str) -> bool:
                return module_name in {"docx", "openpyxl", "fitz"}

            def fake_executable_available(executable_name: str) -> bool:
                return executable_name == "tesseract"

            with patch.object(
                archive_services,
                "derived_text_python_module_available",
                side_effect=fake_module_available,
            ), patch.object(
                archive_services,
                "derived_text_executable_available",
                side_effect=fake_executable_available,
            ):
                code, output = self.run_cli(
                    ["derive-text-doctor", str(archive_root), "--dry-run", "--format", "json"]
                )
                nested_code, nested_output = self.run_cli(
                    ["derive-text", "doctor", str(archive_root), "--dry-run", "--format", "json"]
                )

            result = json.loads(output)
            nested = json.loads(nested_output)
            serialized = json.dumps(result, ensure_ascii=False)
            self.assertEqual(code, 0, output)
            self.assertEqual(nested_code, 0, nested_output)
            self.assertTrue(result["ok"])
            self.assertEqual(result["lifecycle_action"], "derived_text_toolchain_doctor")
            self.assertEqual(nested["lifecycle_action"], "derived_text_toolchain_doctor")
            self.assertTrue(result["dry_run"])
            self.assertEqual(result["would_change"], [])
            self.assertFalse(result["closed_actions"]["source_file_body_read"])
            self.assertFalse(result["closed_actions"]["provider_api_called"])
            self.assertFalse(result["privacy_guards"]["tool_paths_echoed"])
            self.assertFalse(result["privacy_guards"]["import_paths_echoed"])
            self.assertIn("office_open_xml_word", [item["format_family"] for item in result["family_readiness"]])
            by_family = {item["format_family"]: item for item in result["family_readiness"]}
            self.assertTrue(by_family["office_open_xml_word"]["ready"])
            self.assertTrue(by_family["office_open_xml_spreadsheet"]["ready"])
            self.assertTrue(by_family["pdf"]["ready"])
            self.assertTrue(by_family["image_scan"]["ready"])
            self.assertFalse(by_family["office_open_xml_presentation"]["ready"])
            self.assertFalse(by_family["legacy_office_binary"]["ready"])
            self.assertFalse(by_family["audio"]["ready"])
            self.assertNotIn("python-docx", result["readiness_summary"]["missing_tools"])
            self.assertNotIn("python-docx", by_family["office_open_xml_word"]["missing_tools"])
            self.assertIn("python-pptx", by_family["office_open_xml_presentation"]["missing_tools"])
            self.assertIn("LibreOffice", by_family["legacy_office_binary"]["missing_tools"])
            self.assertIn("local ASR", by_family["audio"]["missing_tools"])
            self.assertNotIn(str(archive_root.resolve()), serialized)
            self.assertNotIn(r"C:\Users", serialized)
            self.assertEqual(self._inventory(archive_root), before)

    def test_derive_text_doctor_accepts_tool_hint_paths_without_echoing_them(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            archive_root = self._sandbox(tmp, "archive:personal:derived-hints")
            before = self._inventory(archive_root)
            tools_dir = Path(tmp) / "tools with spaces"
            tools_dir.mkdir()
            soffice = tools_dir / "soffice.exe"
            tesseract = tools_dir / "tesseract.exe"
            soffice.write_text("fake executable marker\n", encoding="utf-8")
            tesseract.write_text("fake executable marker\n", encoding="utf-8")
            hints = Path(tmp) / "tool-hints.json"
            hints.write_text(
                json.dumps(
                    {
                        "schema": "wom-kit/derived-text-tool-hints/v0.1",
                        "executables": {
                            "soffice": str(soffice),
                            "tesseract": [str(tesseract)],
                            "unknown-tool": str(tools_dir / "ignored.exe"),
                        },
                    }
                ),
                encoding="utf-8",
            )

            with patch.object(archive_services, "derived_text_executable_available", return_value=False):
                code, output = self.run_cli(
                    [
                        "derive-text-doctor",
                        str(archive_root),
                        "--tool-hints",
                        str(hints),
                        "--dry-run",
                        "--format",
                        "json",
                    ]
                )

            result = json.loads(output)
            serialized = json.dumps(result, ensure_ascii=False)
            self.assertEqual(code, 0, output)
            self.assertTrue(result["ok"])
            self.assertEqual(result["readiness_summary"]["tool_hints"]["accepted_probe_count"], 2)
            self.assertEqual(result["readiness_summary"]["tool_hints"]["ignored_probe_count"], 1)
            self.assertFalse(result["readiness_summary"]["tool_hints"]["path_echoed"])
            self.assertIn("tool_hints_unknown_executable_probe_ignored", result["warnings"])
            self.assertFalse(result["privacy_guards"]["tool_hint_paths_echoed"])
            by_family = {item["format_family"]: item for item in result["family_readiness"]}
            self.assertTrue(by_family["legacy_office_binary"]["ready"])
            self.assertTrue(by_family["image_scan"]["ready"])
            self.assertNotIn("LibreOffice", result["readiness_summary"]["missing_tools"])
            self.assertNotIn("Tesseract OCR", result["readiness_summary"]["missing_tools"])
            checks_by_probe = {item["probe"]: item for item in result["tool_checks"]}
            self.assertTrue(checks_by_probe["soffice"]["hint_probe_available"])
            self.assertFalse(checks_by_probe["soffice"]["path_probe_available"])
            self.assertTrue(checks_by_probe["tesseract"]["hint_probe_available"])
            self.assertNotIn(str(tools_dir), serialized)
            self.assertNotIn(str(soffice), serialized)
            self.assertNotIn(str(tesseract), serialized)
            self.assertNotIn(str(hints), serialized)
            self.assertEqual(self._inventory(archive_root), before)

    def test_doctor_flags_malformed_derived_text_manifest(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            archive_root = self._sandbox(tmp, "archive:personal:derived-doctor")
            source_object_id = self._derived_text_source_object(archive_root)
            manifest = archive_root / archive_services.DERIVED_TEXT_MANIFEST_RELATIVE_PATH
            manifest.write_text(
                json.dumps(
                    {
                        "schema": archive_services.DERIVED_TEXT_RECORD_SCHEMA,
                        "derived_text_id": "derived-text:sha256:" + "a" * 64,
                        "source_object_id": source_object_id,
                        "derivation_kind": "screen-scrape",
                        "tool_name": "fake",
                        "tool_version": "1",
                        "review_status": "maybe",
                        "text_sha256": "c" * 64,
                        "text_logical_key": "objects/derived-text/sha256/cc/" + "c" * 64 + ".txt",
                        "provenance": {},
                    },
                    separators=(",", ":"),
                )
                + "\n",
                encoding="utf-8",
            )
            code, output = self.run_cli(["doctor", str(archive_root), "--format", "json"])
            self.assertEqual(code, 1, output)
            self.assertIn("derived_text_derivation_kind_invalid", output)
            self.assertIn("derived_text_review_status_invalid", output)


